-- 1. 先查询是否已有默认类别，如果没有则创建
INSERT IGNORE INTO material_categories (name, code, description, sortOrder, createdAt, updatedAt)
VALUES ('系统默认', 'SYS-DEFAULT', '系统默认类别', 0, NOW(), NOW());

-- 2. 获取默认类别ID
SET @defaultCategoryId = (SELECT id FROM material_categories WHERE code = 'SYS-DEFAULT' LIMIT 1);

-- 3. 创建系统默认供应商（使用INSERT IGNORE避免重复）
INSERT IGNORE INTO material_suppliers (categoryId, name, code, contactPerson, status, notes, createdAt, updatedAt)
VALUES (@defaultCategoryId, '系统默认', 'SYS-DEFAULT', '系统', 'active', '系统默认供应商，用于默认布料颜色', NOW(), NOW());

-- 4. 获取供应商ID
SET @defaultSupplierId = (SELECT id FROM material_suppliers WHERE code = 'SYS-DEFAULT' LIMIT 1);

-- 5. 创建默认布板（使用INSERT IGNORE避免重复）
INSERT IGNORE INTO material_boards (supplierId, boardNumber, boardName, pricePerMeter, status, notes, createdAt, updatedAt)
VALUES (@defaultSupplierId, 'DEFAULT-BOARD', '默认布板', 0, 'active', '系统默认布板，用于默认布料颜色', NOW(), NOW());

-- 6. 获取布板ID
SET @defaultBoardId = (SELECT id FROM material_boards WHERE boardNumber = 'DEFAULT-BOARD' AND supplierId = @defaultSupplierId LIMIT 1);

-- 7. 创建默认颜色（使用INSERT IGNORE避免重复）
INSERT IGNORE INTO material_colors (boardId, colorCode, colorName, imageUrl, stockQuantity, status, notes, createdAt, updatedAt)
VALUES (@defaultBoardId, 'DEFAULT-001', '未选-七彩色', 'https://files.manuscdn.com/user_upload_by_module/session_file/310519663334223494/OjqPhcBgxLDYsVOk.png', 999999, 'active', '系统默认颜色，所有批次默认使用', NOW(), NOW());

-- 8. 查询并返回默认颜色ID
SELECT id as defaultColorId FROM material_colors WHERE colorCode = 'DEFAULT-001' AND boardId = @defaultBoardId LIMIT 1;

